function ema(a,p){const k=2/(p+1);let e=a[0];for(const v of a)e=v*k+e*(1-k);return e;}
function rsi(c,p=14){if(c.length<p+1)return 50;let g=0,l=0;for(let i=c.length-p;i<c.length;i++){const d=c[i]-c[i-1];if(d>0)g+=d;else l-=d;}return 100-100/(1+g/(l||0.001));}
function boll(c,p=20,m=2){const sl=c.slice(-p),mid=sl.reduce((a,b)=>a+b,0)/p,sd=Math.sqrt(sl.reduce((a,b)=>a+(b-mid)**2,0)/p);return{upper:mid+m*sd,lower:mid-m*sd,mid};}
function macdFn(c){const line=ema(c.slice(-26),12)-ema(c,26);return{line,signal:line*0.85};}
function vwapFn(H,L,C,V){let t=0,v=0;const n=Math.min(H.length,L.length,C.length,V.length);for(let i=0;i<n;i++){t+=(H[i]+L[i]+C[i])/3*V[i];v+=V[i];}return v>0?t/v:C[C.length-1];}
const cfg=items[0].json,flags=cfg._flags||{};
let stocks=[];
const q=cfg.data||cfg.quotes?.data;
if(flags.hasZerodha&&q){stocks=Object.entries(q).map(([k,v])=>({symbol:k.replace('NSE:',''),ltp:v.last_price,open:v.ohlc.open,high:v.ohlc.high,low:v.ohlc.low,close:v.ohlc.close,volume:v.volume,change:v.change,_mock:false}));}
else{const syms=(cfg.WATCHLIST||'RELIANCE,TCS,INFY,HDFCBANK,ICICIBANK').split(',');stocks=syms.map(s=>{const b=800+Math.random()*2200;return{symbol:s.trim(),ltp:+b.toFixed(2),open:+(b*.99).toFixed(2),high:+(b*1.015).toFixed(2),low:+(b*.975).toFixed(2),close:+(b*1.001).toFixed(2),volume:Math.floor(500000+Math.random()*3e6),change:+((Math.random()-.35)*5).toFixed(2),_mock:true};});}
const hl=(cfg.articles||[]).map(a=>a.title||'').join(' ').toLowerCase();
const geoScore=hl.includes('war')||hl.includes('crash')?35:hl.includes('growth')||hl.includes('rally')?75:55;
const budget=cfg.DAILY_BUDGET||1000,maxS=cfg.MAX_STOCKS||5,profitPct=cfg.PROFIT_TARGET_PCT||20,slPct=cfg.STOPLOSS_PCT||2;
const scored=stocks.map(s=>{const closes=Array.from({length:30},()=>s.close*(.93+Math.random()*.14)),highs=closes.map(c=>c*(1+Math.random()*.02)),lows=closes.map(c=>c*(1-Math.random()*.02)),volumes=closes.map(()=>s.volume*(.7+Math.random()*.6));const RSI=rsi(closes),MACD=macdFn(closes),BB=boll(closes),EMA9=ema(closes,9),EMA21=ema(closes,21),VWAP=vwapFn(highs,lows,closes,volumes),avgVol=volumes.slice(-20).reduce((a,b)=>a+b,0)/20,volSurge=volumes[volumes.length-1]>avgVol*1.5;let score=0;if(RSI>40&&RSI<70)score+=25;if(MACD.line>MACD.signal)score+=20;if(EMA9>EMA21)score+=15;if(s.ltp<BB.lower+(BB.mid-BB.lower)*.25)score+=15;if(s.ltp>VWAP)score+=10;if(volSurge)score+=10;if(s.change>0&&s.change<3)score+=5;const qty=Math.max(1,Math.floor((budget/maxS)/s.ltp));return{symbol:s.symbol,ltp:s.ltp,change:s.change,techScore:score,rsi:+RSI.toFixed(1),macdBull:MACD.line>MACD.signal,emaBull:EMA9>EMA21,aboveVWAP:s.ltp>VWAP,volSurge,qty,costToTrade:+(qty*s.ltp).toFixed(2),stopLoss:+(s.ltp*(1-slPct/100)).toFixed(2),target:+(s.ltp*(1+profitPct/100)).toFixed(2),_mock:s._mock};}).sort((a,b)=>b.techScore-a.techScore);
let rem=budget;const topPicks=[];for(const s of scored){if(topPicks.length>=maxS)break;if(s.costToTrade<=rem){topPicks.push(s);rem-=s.costToTrade;}}
return[{json:{...cfg,techAnalysis:scored,topPicks,geoScore,newsHeadlines:(cfg.articles||[]).slice(0,5).map(a=>a.title),budgetUsed:+(budget-rem).toFixed(2),budgetLeft:+rem.toFixed(2),analysisTime:new Date().toISOString()}}];

function parseAI(r){if(!r)return[];try{const s=(typeof r==='string'?r:JSON.stringify(r)).replace(/```json/gi,'').replace(/```/g,'').trim();const p=JSON.parse(s);return Array.isArray(p)?p:[];}catch{return[];}}
const d=items[0].json;
const cr=parseAI(d.claudeResp?.content?.[0]?.text),gr=parseAI(d.geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text),gkr=parseAI(d.grokResp?.choices?.[0]?.message?.content),pr=parseAI(d.perplexResp?.choices?.[0]?.message?.content);
const all=[...cr,...gr,...gkr,...pr],ac=[cr,gr,gkr,pr].filter(x=>x.length>0).length;
const m={};for(const r of all){if(!r.symbol)continue;if(!m[r.symbol])m[r.symbol]={buyScore:0,count:0,reasons:[]};m[r.symbol].buyScore+=r.rec==='BUY'?(r.confidence||50):0;m[r.symbol].count++;if(r.reason)m[r.symbol].reasons.push(r.reason);}
const fp=(d.topPicks||[]).map(p=>{const ai=m[p.symbol]||{buyScore:0,count:0,reasons:['Tech only']};const aiS=ai.count>0?ai.buyScore/ai.count:50,geo=d.geoScore||55,tw=ac>0?.50:.70,aw=ac>0?.30:0,gw=1-tw-aw,comp=p.techScore*tw+aiS*aw+geo*gw;return{...p,aiScore:+aiS.toFixed(1),geoScore:geo,composite:+comp.toFixed(1),recommendation:comp>=55?'BUY':'SKIP',aiReasons:ai.reasons.slice(0,2),advisorsUsed:ac};}).filter(p=>p.recommendation==='BUY').sort((a,b)=>b.composite-a.composite);
return[{json:{...d,finalPicks:fp,hasBuySignals:fp.length>0,advisorsUsed:ac}}];

