const fs=require('fs');
const d=items[0].json,live=d.data||{},open=d.openTrades||[];
const now=new Date(),ist=t=>new Intl.DateTimeFormat('en-IN',{...t,timeZone:'Asia/Kolkata'}).format(now);
const h=parseInt(ist({hour:'numeric',hour12:false})),m=parseInt(ist({minute:'numeric'}));
const isEOD=h===15&&m>=10,timeStr=now.toLocaleString('en-IN',{timeZone:'Asia/Kolkata'});
const toSell=[],stillOpen=[];let totalPnL=0;
for(const t of open){
  const ltp=live['NSE:'+t.symbol]?.last_price||t.entryPrice;
  const pnl=(ltp-t.entryPrice)*t.qty,pnlPct=((ltp-t.entryPrice)/t.entryPrice)*100;
  totalPnL+=pnl;
  const hitTarget=ltp>=t.target,hitSL=ltp<=t.stopLoss;
  if(hitTarget||hitSL||isEOD)toSell.push({...t,ltp,pnl:+pnl.toFixed(2),pnlPct:+pnlPct.toFixed(2),exitReason:hitTarget?'TARGET_HIT':hitSL?'STOPLOSS_HIT':'EOD_SQUAREOFF',exitTime:timeStr,status:'CLOSING'});
  else stillOpen.push({...t,ltp,pnl:+pnl.toFixed(2),pnlPct:+pnlPct.toFixed(2)});
}
const allDone=stillOpen.length===0&&open.length>0;
if(d.stateFile)try{
  const s=JSON.parse(fs.readFileSync(d.stateFile,'utf8'));
  s.trades=[...toSell.map(t=>({...t,status:'CLOSED'})),...stillOpen];
  s.lastMonitorAt=now.toISOString();s.sessionClosed=isEOD||allDone;s.totalPnL=+totalPnL.toFixed(2);
  fs.writeFileSync(d.stateFile,JSON.stringify(s,null,2));
}catch{}
return[{json:{...d,toSell,stillOpen,totalPnL:+totalPnL.toFixed(2),hasExits:toSell.length>0,allTargetsHit:toSell.every(t=>t.exitReason==='TARGET_HIT')&&stillOpen.length===0&&toSell.length>0,isEOD,timeStr}}];

