const eLines=exits.map(t=>`${em(t.exitReason)} *${t.symbol}* — ${t.exitReason.replace(/_/g,' ')}
   Entry:₹${t.entryPrice} Exit:₹${t.ltp} | ${t.pnl>=0?'+':''}₹${t.pnl}(${t.pnlPct>=0?'+':''}${t.pnlPct}%)`).join('
');
